import React from "react";
import { Link } from "react-router-dom";
import { cilCaretLeft } from "@coreui/icons";
import CIcon from "@coreui/icons-react";

const GoBackComponent = (props) => {
    return (
        <div className="col-md-12 mb-3">
            <div className="filterSection">
                <div className="topglobal">
                    <Link className="goback" to={`/${props.goBackData}`} state={props.goBackStateData} style={{textDecoration: "none", fontSize: "15px"}}>
                        <CIcon icon={cilCaretLeft} className="me-2" />Go Back
                    </Link>
                </div>
            </div>
        </div>
    )
}

export default GoBackComponent;
